contracts/Escrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title FreelanceEscrow
 * @dev Secure milestone-based payment system for freelancers and clients.
 */
contract FreelanceEscrow is ReentrancyGuard, Ownable {

    enum MilestoneStatus { Pending, Funded, Submitted, Approved, Disputed, Resolved }

    struct Milestone {
        string description;
        uint256 amount;
        MilestoneStatus status;
    }

    struct Project {
        address client;
        address freelancer;
        uint256 totalAmount;
        uint256 milestoneCount;
        bool isFunded;
        mapping(uint256 => Milestone) milestones;
    }

    uint256 public projectCount;
    mapping(uint256 => Project) public projects;

    event ProjectCreated(uint256 indexed projectId, address indexed client, address indexed freelancer, uint256 totalAmount);
    event ProjectFunded(uint256 indexed projectId, uint256 amount);
    event MilestoneSubmitted(uint256 indexed projectId, uint256 indexed milestoneId);
    event MilestoneApproved(uint256 indexed projectId, uint256 indexed milestoneId, uint256 amount);
    event DisputeRaised(uint256 indexed projectId, uint256 indexed milestoneId);
    event DisputeResolved(uint256 indexed projectId, uint256 indexed milestoneId, bool releasedToFreelancer);

    constructor() Ownable(msg.sender) {}

    /**
     * @dev Create a new project with milestones.
     */
    function createProject(
        address _freelancer,
        string[] memory _descriptions,
        uint256[] memory _amounts
    ) external returns (uint256) {
        require(_freelancer != address(0), "Invalid freelancer address");
        require(_descriptions.length == _amounts.length, "Mismatching milestone data");
        require(_descriptions.length > 0, "No milestones provided");

        projectCount++;
        Project storage project = projects[projectCount];
        project.client = msg.sender;
        project.freelancer = _freelancer;
        project.milestoneCount = _descriptions.length;

        uint256 total = 0;
        for (uint256 i = 0; i < _descriptions.length; i++) {
            project.milestones[i] = Milestone({
                description: _descriptions[i],
                amount: _amounts[i],
                status: MilestoneStatus.Pending
            });
            total += _amounts[i];
        }
        project.totalAmount = total;

        emit ProjectCreated(projectCount, msg.sender, _freelancer, total);
        return projectCount;
    }

    /**
     * @dev Fund the project escrow.
     */
    function fundProject(uint256 _projectId) external payable nonReentrant {
        Project storage project = projects[_projectId];
        require(msg.sender == project.client, "Only client can fund");
        require(!project.isFunded, "Already funded");
        require(msg.value == project.totalAmount, "Incorrect funding amount");

        project.isFunded = true;
        for (uint256 i = 0; i < project.milestoneCount; i++) {
            project.milestones[i].status = MilestoneStatus.Funded;
        }

        emit ProjectFunded(_projectId, msg.value);
    }

    /**
     * @dev Freelancer submits a milestone for review.
     */
    function submitMilestone(uint256 _projectId, uint256 _milestoneId) external {
        Project storage project = projects[_projectId];
        require(msg.sender == project.freelancer, "Only freelancer can submit");
        require(project.milestones[_milestoneId].status == MilestoneStatus.Funded, "Invalid milestone status");

        project.milestones[_milestoneId].status = MilestoneStatus.Submitted;
        emit MilestoneSubmitted(_projectId, _milestoneId);
    }

    /**
     * @dev Client approves milestone and releases payment.
     */
    function approveMilestone(uint256 _projectId, uint256 _milestoneId) external nonReentrant {
        Project storage project = projects[_projectId];
        require(msg.sender == project.client, "Only client can approve");

        Milestone storage milestone = project.milestones[_milestoneId];
        require(milestone.status == MilestoneStatus.Submitted, "Milestone not submitted");

        uint256 amount = milestone.amount;
        milestone.status = MilestoneStatus.Approved;

        (bool success, ) = payable(project.freelancer).call{value: amount}("");
        require(success, "Transfer failed");

        emit MilestoneApproved(_projectId, _milestoneId, amount);
    }

    /**
     * @dev Raise a dispute for a milestone.
     */
    function disputeMilestone(uint256 _projectId, uint256 _milestoneId) external {
        Project storage project = projects[_projectId];
        require(msg.sender == project.client || msg.sender == project.freelancer, "Not authorized");

        Milestone storage milestone = project.milestones[_milestoneId];
        require(milestone.status == MilestoneStatus.Submitted, "Cannot dispute");

        milestone.status = MilestoneStatus.Disputed;
        emit DisputeRaised(_projectId, _milestoneId);
    }

    /**
     * @dev Resolve a dispute (Admin only for hackathon demo simplicity).
     */
    function resolveDispute(uint256 _projectId, uint256 _milestoneId, bool _releaseToFreelancer) external onlyOwner nonReentrant {
        Project storage project = projects[_projectId];
        Milestone storage milestone = project.milestones[_milestoneId];
        require(milestone.status == MilestoneStatus.Disputed, "Not in dispute");

        milestone.status = MilestoneStatus.Resolved;

        if (_releaseToFreelancer) {
            (bool success, ) = payable(project.freelancer).call{value: milestone.amount}("");
            require(success, "Transfer to freelancer failed");
        } else {
            (bool success, ) = payable(project.client).call{value: milestone.amount}("");
            require(success, "Refund to client failed");
        }

        emit DisputeResolved(_projectId, _milestoneId, _releaseToFreelancer);
    }

    // Helper to get milestone details (mappings can't be returned directly)
    function getMilestone(uint256 _projectId, uint256 _milestoneId) external view returns (string memory, uint256, MilestoneStatus) {
        Milestone storage m = projects[_projectId].milestones[_milestoneId];
        return (m.description, m.amount, m.status);
    }
}

